from math import factorial
def A345684(n):
    c, j, f = 0, 1, factorial(n)
    while j <= n:
        k = n//j
        m = n//k
        c += f*(m+j)*(m-j+1)//k
        j = m+1
    return c>>1 # _Chai Wah Wu_, May 13 2026

